import{_ as a,o as t,c as o,a2 as l}from"./chunks/framework.DGp-bpT-.js";const p=JSON.parse('{"title":"Скилы (Bot Skills)","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://srebot.site360.tech/docs/guide/skills.md"}],["link",{"rel":"alternate","hreflang":"ru","href":"https://srebot.site360.tech/docs/guide/skills.md"}],["link",{"rel":"alternate","hreflang":"en","href":"https://srebot.site360.tech/docs/en/guide/skills.md"}],["link",{"rel":"alternate","hreflang":"x-default","href":"https://srebot.site360.tech/docs/guide/skills.md"}]]},"headers":[],"relativePath":"guide/skills.md","filePath":"guide/skills.md","lastUpdated":null}'),r={name:"guide/skills.md"};function i(s,e,n,d,c,h){return t(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="скилы-bot-skills" tabindex="-1">Скилы (Bot Skills) <a class="header-anchor" href="#скилы-bot-skills" aria-label="Permalink to &quot;Скилы (Bot Skills)&quot;">​</a></h1><p>Скилы — это настраиваемые текстовые инструкции (в формате Markdown), позволяющие адаптировать поведение LLM-агента SREBot под специфику инфраструктуры вашей организации без внесения изменений в код бота.</p><h2 id="зачем-нужны-скилы" tabindex="-1">Зачем нужны скилы? <a class="header-anchor" href="#зачем-нужны-скилы" aria-label="Permalink to &quot;Зачем нужны скилы?&quot;">​</a></h2><p>По умолчанию SREBot использует общие алгоритмы анализа логов и метрик, однако в реальных проектах инфраструктура часто имеет уникальные особенности:</p><ul><li>Специфические форматы логирования (например, имя приложения находится во вложенном поле <code>json.appname</code> или <code>json.app_name</code>, а не <code>app_name</code>).</li><li>Нестандартное размещение метрик или кастомные PromQL-запросы.</li><li>Уникальные ссылки на внутренние системы логирования (Kibana, Loki) или документацию.</li></ul><p>Скилы позволяют передать эти знания модели при расследовании инцидентов.</p><hr><h2 id="создание-скила" tabindex="-1">Создание скила <a class="header-anchor" href="#создание-скила" aria-label="Permalink to &quot;Создание скила&quot;">​</a></h2><p>Чтобы создать скил, перейдите в раздел <strong>Скилы</strong> в боковом меню дашборда и нажмите кнопку <strong>Создать скил</strong>.</p><p>Форма создания скила состоит из следующих полей:</p><h3 id="_1-метаданные" tabindex="-1">1. Метаданные <a class="header-anchor" href="#_1-метаданные" aria-label="Permalink to &quot;1. Метаданные&quot;">​</a></h3><ul><li><strong>Название (Name):</strong> Понятное имя скила (например, <code>Правила парсинга логов worker-billing</code>).</li><li><strong>Описание (Description):</strong> Краткое описание назначения скила.</li></ul><h3 id="_2-область-видимости-scope" tabindex="-1">2. Область видимости (Scope) <a class="header-anchor" href="#_2-область-видимости-scope" aria-label="Permalink to &quot;2. Область видимости (Scope)&quot;">​</a></h3><p>Определяет, для каких именно агентов будут применены инструкции:</p><ul><li><strong>Организация (Organization):</strong> Инструкции будут применяться для всех ботов внутри вашей организации.</li><li><strong>Конкретный бот (Specific Bot):</strong> Инструкции привязываются только к выбранным ботам.</li></ul><h3 id="_3-правила-триггеров-trigger-rules" tabindex="-1">3. Правила триггеров (Trigger Rules) <a class="header-anchor" href="#_3-правила-триггеров-trigger-rules" aria-label="Permalink to &quot;3. Правила триггеров (Trigger Rules)&quot;">​</a></h3><p>Позволяют автоматически активировать скил только для определенных алертов. Вы можете указать набор правил в формате <code>Ключ: Регулярное выражение</code>:</p><ul><li>Например: <code>namespace: production</code>, <code>alertname: OOMKilled</code>.</li><li>Если правила триггеров не заданы, скил будет являться <strong>общим (catch-all)</strong> и применяться ко всем инцидентам в выбранной области видимости.</li></ul><h3 id="_4-инструкция-markdown-instructions" tabindex="-1">4. Инструкция (Markdown Instructions) <a class="header-anchor" href="#_4-инструкция-markdown-instructions" aria-label="Permalink to &quot;4. Инструкция (Markdown Instructions)&quot;">​</a></h3><p>Свободный текст в формате Markdown, который описывает правила и контекст. Этот текст динамически подмешивается в системный промпт LLM-модели.</p><hr><h2 id="принцип-работы" tabindex="-1">Принцип работы <a class="header-anchor" href="#принцип-работы" aria-label="Permalink to &quot;Принцип работы&quot;">​</a></h2><p>При получении нового алерта бэкенд SREBot автоматически выполняет следующие шаги:</p><ol><li><strong>Извлечение метаданных:</strong> Извлекаются все метки (labels) и аннотации (annotations) из входящего алерта.</li><li><strong>Матчинг триггеров:</strong> На основе регулярных выражений проверяются правила триггеров для всех активных скилов организации.</li><li><strong>Сортировка по приоритету:</strong> Все подошедшие скилы сортируются по области видимости: сначала <strong>Глобальные (Global)</strong>, затем <strong>Организационные (Organization)</strong>, и в последнюю очередь <strong>Локальные (Bot-specific)</strong>. Инструкции конкретного бота имеют наивысший приоритет благодаря расположению в конце системного промпта.</li><li><strong>Инъекция в промпт:</strong> Сформированный блок инструкций добавляется в системное сообщение LLM перед запуском цикла расследования.</li></ol>',24)])])}const u=a(r,[["render",i]]);export{p as __pageData,u as default};
